-- SFL Command Center Phase 3: Team Rosters
-- Run this complete file once in Supabase SQL Editor.

begin;

create table if not exists public.roster_players (
  id uuid primary key default gen_random_uuid(),
  source_key text not null unique,
  team_id uuid not null references public.teams(id) on delete cascade,
  roster_order integer not null default 0,
  display_name text not null,
  position text not null,
  height text,
  weight text,
  college_entry text,
  acquisition_entry text,
  contract_terms text,
  signing_bonus text,
  cap_hit text,
  years_remaining integer,
  player_stats jsonb not null default '{}'::jsonb,
  roster_status text not null default 'Active',
  photo_url text,
  age_text text,
  raw_record jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists roster_players_team_idx
  on public.roster_players(team_id, roster_order);

create index if not exists roster_players_name_idx
  on public.roster_players(display_name);

drop trigger if exists roster_players_set_updated_at on public.roster_players;
create trigger roster_players_set_updated_at
before update on public.roster_players
for each row execute function public.set_updated_at();

alter table public.roster_players enable row level security;

drop policy if exists "Public read roster players" on public.roster_players;
create policy "Public read roster players"
on public.roster_players for select
to anon, authenticated
using (true);

commit;

begin;

