on conflict (source_key) do update set
  team_id = excluded.team_id,
  roster_order = excluded.roster_order,
  display_name = excluded.display_name,
  position = excluded.position,
  height = excluded.height,
  weight = excluded.weight,
  college_entry = excluded.college_entry,
  acquisition_entry = excluded.acquisition_entry,
  contract_terms = excluded.contract_terms,
  signing_bonus = excluded.signing_bonus,
  cap_hit = excluded.cap_hit,
  years_remaining = excluded.years_remaining,
  player_stats = excluded.player_stats,
  roster_status = excluded.roster_status,
  photo_url = excluded.photo_url,
  age_text = excluded.age_text,
  raw_record = excluded.raw_record;

commit;

select
  count(*) as total_roster_players,
  count(distinct team_id) as teams_loaded
from public.roster_players;
